            aWandererG = aWandererG + ((((RotL64(aIngress, 13U) + aOrbiterG) + RotL64(aOrbiterI, 41U)) + RotL64(aCarry, 47U)) + aPhaseEWandererUpdateSaltC[(((31U - aIndex) + 9U)) & 31]);
