            aIngress = aIngress + (RotL64(aOrbiterA, 26U) ^ aOrbiterC);
            aIngress = aIngress + (aOrbiterJ ^ RotL64(aOrbiterD, 53U));
            aIngress = aIngress + (RotL64(aOrbiterB, 47U) ^ aOrbiterK);
