            //
            aWandererB = aWandererB + ((((RotL64(aCross, 11U) + RotL64(aOrbiterG, 34U)) + aOrbiterD) + RotL64(aCarry, 21U)) + aPhaseDWandererUpdateSaltB[(((31U - aIndex) + 11U)) & 31]);
