            aOrbiterB = ((aWandererE + RotL64(aCross, 23U)) + 0x0B23C5AB55DD59F4ULL) + aPhaseGOrbiterAssignSaltB[(((31U - aIndex) + 27U)) & 31];
            //
            aOrbiterF = (aOrbiterF + aOrbiterE) + 0x9CA881F104B8D66FULL;
