            //
            aOrbiterJ = (aOrbiterJ + aOrbiterI) + 0x7DA9AA437750A63DULL;
            aOrbiterA = (aOrbiterA ^ aOrbiterJ) ^ 0x5E909D67DE090AEBULL;
